function initializeLanguage() {
    setLanguage(
        new URLSearchParams(window.location.search).get("lang") ||
            localStorage.getItem("preferredLanguage") ||
            "zh-CN",
    );
}
function setLanguage(e) {
    (localStorage.setItem("preferredLanguage", e),
        (document.documentElement.lang = e));
    document.querySelectorAll(".language-btn").forEach((t) => {
        ("zh" === t.dataset.lang && "zh-CN" === e) ||
        (t.dataset.lang == t.dataset.lang && e === t.dataset.lang)
            ? t.classList.add("active")
            : t.classList.remove("active");
    });
}
function initializeLanguageButtons() {
    document.querySelectorAll(".language-btn").forEach((e) => {
        e.addEventListener("click", () => {
            const t = e.dataset.lang;
            setLanguage("zh" === t ? "zh-CN" : t);
            const a = new URL(window.location.href);
            (a.searchParams.set("lang", t),
                window.history.pushState({}, "", a));
        });
    });
}
document.addEventListener("DOMContentLoaded", function () {
    (initializeLanguage(),
        generateDayGrid(),
        initializeLanguageCards(),
        initializeScrollAnimations(),
        initializeDayPagination(),
        initializeMicroInteractions(),
        initializeLanguageButtons());
    const e = document.querySelector(".hero-section");
    if (e) {
        const t = new Image();
        ((t.onload = function () {
            e.classList.add("loaded");
        }),
            (t.src =
                "https://images.unsplash.com/photo-1546410531-89436e5b419a?auto=format&fit=crop&w=900&q=75"));
    }
    document.querySelectorAll("section").forEach((e) => {
        e.classList.contains("hero-section") ||
            ((e.style.contentVisibility = "auto"),
            (e.style.containIntrinsicSize = "500px"));
    });
});
let currentDayPage = 1;
const daysPerPage = 10,
    totalDays = 40;
let selectedLanguage = localStorage.getItem("preferredLanguage") || "zh-CN";
function generateDayGrid() {
    const e = document.querySelector(".day-grid");
    e.innerHTML = "";
    const t = (currentDayPage - 1) * daysPerPage + 1,
        a = Math.min(t + daysPerPage - 1, totalDays);
    document.getElementById("dayRangeStart") &&
        ((document.getElementById("dayRangeStart").textContent = t),
        (document.getElementById("dayRangeEnd").textContent = a));
    for (let n = t; n <= a; n++) {
        const a = document.createElement("a"),
            i = "zh-CN" === selectedLanguage ? "zh" : selectedLanguage;
        ((a.href = `day.html?day=${n}&lang=${i}`),
            (a.className = "animate-fade-in hover-scale"),
            (a.style.animationDelay = 0.05 * (n - t) + "s"));
        const o = document.createElement("div");
        ((o.className = "day-number"), (o.textContent = n));
        const r = document.createElement("div");
        ((r.className = "day-status"),
            (r.innerHTML =
                '<i class="fas fa-circle" style="color: var(--warning-color);"></i>'),
            addDayTooltip(
                a,
                n <= 7
                    ? "Pinyin system, tones, and pronunciation basics"
                    : n <= 14
                      ? "Essential daily phrases and basic grammar"
                      : n <= 22
                        ? "Cultural context and daily life communication"
                        : n <= 30
                          ? "Professional and business Mandarin"
                          : "Advanced fluency and real-world applications",
            ),
            a.appendChild(o),
            a.appendChild(r),
            e.appendChild(a));
    }
    updateProgress(0);
}
function initializeDayPagination() {
    const e = document.getElementById("prevDays"),
        t = document.getElementById("nextDays");
    e &&
        t &&
        (e.addEventListener("click", function () {
            currentDayPage > 1 &&
                (currentDayPage--,
                generateDayGrid(),
                document
                    .querySelector(".day-grid")
                    .classList.add("animate-fade-in"),
                setTimeout(() => {
                    document
                        .querySelector(".day-grid")
                        .classList.remove("animate-fade-in");
                }, 800));
        }),
        t.addEventListener("click", function () {
            currentDayPage < Math.ceil(totalDays / daysPerPage) &&
                (currentDayPage++,
                generateDayGrid(),
                document
                    .querySelector(".day-grid")
                    .classList.add("animate-fade-in"),
                setTimeout(() => {
                    document
                        .querySelector(".day-grid")
                        .classList.remove("animate-fade-in");
                }, 800));
        }));
}
function addDayTooltip(e, t) {
    e.setAttribute("title", t);
}
function initializeLanguageCards() {
    const e = document.querySelectorAll(".language-card"),
        t = { zh: "zh-CN", pinyin: "en", en: "en" };
    e.forEach((e, a) => {
        const n = Object.keys(t)[a];
        n &&
            (e.addEventListener("click", function () {
                const e = t[n];
                (document.querySelectorAll(".language-card").forEach((e) => {
                    ((e.style.opacity = "0.7"), (e.style.transform = "none"));
                }),
                    (this.style.opacity = "1"),
                    (this.style.transform = "translateY(-10px)"),
                    setLanguage(e),
                    updateDayGridLanguage(n),
                    document
                        .querySelector("#day-selection")
                        .scrollIntoView({
                            behavior: "smooth",
                            block: "start",
                        }));
            }),
            e.addEventListener("mouseenter", function () {
                "0.7" !== this.style.opacity &&
                    ((this.style.transform = "translateY(-10px)"),
                    (this.style.boxShadow = "0 15px 30px rgba(0,0,0,0.15)"));
            }),
            e.addEventListener("mouseleave", function () {
                "0.7" !== this.style.opacity &&
                    ((this.style.transform = "translateY(0)"),
                    (this.style.boxShadow = "0 10px 20px rgba(0,0,0,0.1)"));
            }));
    });
}
function updateDayGridLanguage(e) {
    document.querySelectorAll(".day-grid a").forEach((t) => {
        const a = t.querySelector(".day-number").textContent;
        t.href = `day.html?day=${a}&lang=${e}`;
    });
}
function initializeScrollAnimations() {
    const e = new IntersectionObserver(
        (t) => {
            t.forEach((t) => {
                t.isIntersecting &&
                    (t.target.classList.contains("section-card")
                        ? t.target.classList.add("animate-slide-right")
                        : t.target.classList.contains("benefit-card")
                          ? t.target.classList.add("animate-slide-left")
                          : t.target.classList.add("animate-fade-in"),
                    e.unobserve(t.target));
            });
        },
        { threshold: 0.1 },
    );
    (document
        .querySelectorAll(
            "section, .language-card, .section-card, .benefit-card, .section-divider",
        )
        .forEach((t) => {
            t.classList.contains("animate-fade-in") ||
                t.classList.contains("animate-slide-right") ||
                t.classList.contains("animate-slide-left") ||
                e.observe(t);
        }),
        document.querySelectorAll(".visual-anchor").forEach((e) => {
            e.classList.add("animate-float");
        }));
}
function initializeMicroInteractions() {
    (document.querySelectorAll(".section-divider").forEach((e) => {
        e.classList.add("animate-pulse");
    }),
        document.querySelectorAll(".benefit-card").forEach((e) => {
            (e.addEventListener("mouseenter", function () {
                this.style.background =
                    "linear-gradient(135deg, white, #f8f9fa)";
            }),
                e.addEventListener("mouseleave", function () {
                    this.style.background = "white";
                }));
        }),
        document.querySelectorAll(".section-card").forEach((e, t) => {
            (e.addEventListener("mouseenter", function () {
                this.style.borderLeftWidth = "8px";
            }),
                e.addEventListener("mouseleave", function () {
                    this.style.borderLeftWidth = "4px";
                }));
        }));
}
function updateProgress(e) {
    const t = document.querySelectorAll(".progress-fill"),
        a = (e / 40) * 100;
    (t.forEach((e) => {
        e.style.width = `${a}%`;
    }),
        document.querySelectorAll(".progress-container p").forEach((t) => {
            t.textContent = `Progress: Day ${e}/40`;
        }));
}
function formatDate(e) {
    const t = document.documentElement.lang;
    return new Intl.DateTimeFormat("zh-CN" === t ? "zh-CN" : "en-US", {
        weekday: "long",
        year: "numeric",
        month: "long",
        day: "numeric",
    }).format(e);
}
function handleError(e) {
    console.error("An error occurred:", e);
    const t = document.querySelector("main"),
        a = document.createElement("div");
    a.className = "error animate-fade-in";
    const n = document.documentElement.lang;
    ((a.innerHTML =
        "zh-CN" === n
            ? '<span class="zh">发生错误。请稍后再试。</span>'
            : '<span class="en">An error occurred. Please try again later.</span>'),
        t.prepend(a));
}
